import{_ as p,I as l,c as d,o as k,a4 as a,J as s,j as o,a as t,w as n}from"./chunks/framework.BR-X7tCu.js";const y=JSON.parse('{"title":"插件安装指南","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guides/usage/plugin-installation-guide.md","filePath":"docs/guides/usage/plugin-installation-guide.md","lastUpdated":1781970535000}'),c={name:"docs/guides/usage/plugin-installation-guide.md"};function b(u,i,x,F,m,f){const r=l("PluginStats"),e=l("VPNolebaseInlineLinkPreview"),h=l("NolebaseGitContributors"),g=l("NolebaseGitChangelog");return k(),d("div",null,[i[5]||(i[5]=a('<h1 id="插件安装指南" tabindex="-1">插件安装指南 <a class="header-anchor" href="#插件安装指南" aria-label="Permalink to “插件安装指南”">​</a></h1><p>欢迎来到 Neo-MoFox 插件的世界！在这里，你可以找到各种有趣的插件来扩展 Neo-MoFox 的功能。</p><h2 id="插件获取途径" tabindex="-1">插件获取途径 <a class="header-anchor" href="#插件获取途径" aria-label="Permalink to “插件获取途径”">​</a></h2><h3 id="neo-mofox-插件市场-推荐" tabindex="-1">Neo-MoFox 插件市场（推荐） <a class="header-anchor" href="#neo-mofox-插件市场-推荐" aria-label="Permalink to “Neo-MoFox 插件市场（推荐）”">​</a></h3><p>现在推荐优先使用 <strong>Neo-MoFox 插件市场</strong> 获取插件：</p>',5)),s(r),i[6]||(i[6]=a('<p>插件市场可以帮你：</p><ul><li>🔍 <strong>搜索插件</strong>：按插件名称、作者、标签查找插件</li><li>📦 <strong>下载插件包</strong>：在插件详情页直接下载最新版本或指定版本</li><li>🔔 <strong>订阅插件更新</strong>：订阅后可在 <strong>「我的」</strong> 页面集中查看，并可配合访问令牌让 Neo-MoFox 同步订阅</li><li>🧩 <strong>查看插件依赖</strong>：确认插件是否依赖其他前置插件</li><li>💬 <strong>查看评论与评分</strong>：参考其他用户的安装体验</li></ul><div class="danger custom-block"><p class="custom-block-title">安全提醒</p><p>插件市场中的插件由作者自行上传。安装前请确认插件名称、作者、简介、版本、依赖和评论。只安装你信任来源的插件。</p></div><h2 id="安装前必读" tabindex="-1">安装前必读 <a class="header-anchor" href="#安装前必读" aria-label="Permalink to “安装前必读”">​</a></h2><div class="danger custom-block"><p class="custom-block-title">重要提示</p><p>在安装任何插件之前，请<strong>务必</strong>仔细阅读插件详情页、插件说明文档或作者发布说明！这将帮助你了解：</p><ul><li>插件的具体功能和使用方法</li><li>必要的配置步骤</li><li>依赖项要求</li><li>注意事项和已知问题</li><li>插件是否适配你当前的 Neo-MoFox 版本</li></ul></div><h2 id="使用插件市场安装插件" tabindex="-1">使用插件市场安装插件 <a class="header-anchor" href="#使用插件市场安装插件" aria-label="Permalink to “使用插件市场安装插件”">​</a></h2><h3 id="第一步-打开插件市场" tabindex="-1">第一步：打开插件市场 <a class="header-anchor" href="#第一步-打开插件市场" aria-label="Permalink to “第一步：打开插件市场”">​</a></h3>',7)),o("ol",null,[o("li",null,[i[1]||(i[1]=t("打开浏览器，进入 ",-1)),s(e,{href:"https://39.96.71.162/",target:"_blank",rel:"noreferrer"},{default:n(()=>[...i[0]||(i[0]=[t("Neo-MoFox 插件市场",-1)])]),_:1}),i[2]||(i[2]=t("。",-1))]),i[3]||(i[3]=a("<li>如果是第一次进入插件市场，会先看到 <strong>「首次使用安全提示」</strong> 弹窗。</li><li>仔细阅读提示后，点击右下角的 <strong>「我已知悉」</strong>。</li><li>随后可能会出现 <strong>「更便利·更轮椅」</strong> 的功能提示弹窗，点击右下角的 <strong>「知道了，不再提示」</strong>。</li><li>进入插件市场首页后，就可以开始查找插件了。</li>",4))]),i[7]||(i[7]=a(`<h3 id="第二步-查找插件" tabindex="-1">第二步：查找插件 <a class="header-anchor" href="#第二步-查找插件" aria-label="Permalink to “第二步：查找插件”">​</a></h3><p>你可以用下面几种方式找到插件：</p><ul><li>在顶部搜索框输入插件名称、作者或标签，然后点击 <strong>「搜索」</strong>。</li><li>点击顶部导航的 <strong>「推荐」</strong>，查看推荐插件。</li><li>点击顶部导航的 <strong>「浏览」</strong>，按分类浏览插件。</li><li>如果已经拿到插件详情页链接，可以直接在浏览器打开。</li></ul><p>进入插件详情页后，请先确认这些信息：</p><ul><li>插件标题是否是你要安装的插件</li><li>插件 ID 是否正确</li><li>作者是否可信</li><li>最新版本号和更新时间是否合理</li><li>插件简介、依赖、评论和评分是否符合预期</li></ul><h3 id="第三步-找到安装面板" tabindex="-1">第三步：找到安装面板 <a class="header-anchor" href="#第三步-找到安装面板" aria-label="Permalink to “第三步：找到安装面板”">​</a></h3><p>插件详情页右侧会有一个 <strong>「安装」</strong> 面板。这个面板通常会显示：</p><ul><li>最新稳定版</li><li>发布时间</li><li>累计下载</li><li>订阅人数</li><li>评分</li><li><strong>「下载插件」</strong> 按钮</li><li><strong>「订阅更新」</strong> 按钮</li></ul><p>如果你的浏览器窗口比较窄，右侧 <strong>「安装」</strong> 面板可能会移动到页面下方。向下滚动就能看到。</p><h3 id="第四步-下载插件" tabindex="-1">第四步：下载插件 <a class="header-anchor" href="#第四步-下载插件" aria-label="Permalink to “第四步：下载插件”">​</a></h3><p>安装最新稳定版：</p><ol><li>在 <strong>「安装」</strong> 面板点击 <strong>「下载插件」</strong>。</li><li>浏览器会打开或下载插件包。</li><li>如果浏览器只是打开了下载链接，请按浏览器提示保存文件。</li><li>下载完成后，保留插件包，继续下一步。</li></ol><p>安装指定版本：</p><ol><li>在插件详情页点击 <strong>「版本」</strong> 标签。</li><li>找到你需要的版本。</li><li>点击该版本右侧的 <strong>「下载」</strong>。</li><li>下载完成后，保留插件包，继续下一步。</li></ol><h3 id="第五步-放入插件目录" tabindex="-1">第五步：放入插件目录 <a class="header-anchor" href="#第五步-放入插件目录" aria-label="Permalink to “第五步：放入插件目录”">​</a></h3><p>将下载到的插件包放入 Neo-MoFox 的插件目录。通常路径是：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;Neo-MoFox安装目录&gt;/plugins/</span></span></code></pre></div><p>常见处理方式：</p><ul><li>如果下载的是 <code>.mfp</code> 插件包，可以直接放入 <code>plugins</code> 目录。</li><li>如果下载的是压缩包，请按插件说明处理；需要解压时，解压后的插件目录应放在 <code>plugins</code> 目录下。</li><li>不要把插件放到 <code>config</code>、<code>data</code>、<code>logs</code> 等目录里。</li></ul><h3 id="第六步-订阅更新-推荐" tabindex="-1">第六步：订阅更新（推荐） <a class="header-anchor" href="#第六步-订阅更新-推荐" aria-label="Permalink to “第六步：订阅更新（推荐）”">​</a></h3><p>回到插件市场的插件详情页，在 <strong>「安装」</strong> 面板点击 <strong>「订阅更新」</strong>。按钮状态变成 <strong>「已订阅」</strong> 后，说明订阅成功。</p><p>订阅成功后，可以点击插件市场顶部导航栏的 <strong>「我的」</strong>，在 <strong>「我的订阅」</strong> 中集中查看已订阅插件。</p><h3 id="第七步-配置访问令牌-用于同步订阅" tabindex="-1">第七步：配置访问令牌（用于同步订阅） <a class="header-anchor" href="#第七步-配置访问令牌-用于同步订阅" aria-label="Permalink to “第七步：配置访问令牌（用于同步订阅）”">​</a></h3><p>如果你希望 Neo-MoFox 主程序主动从插件市场同步你的订阅，需要在插件市场生成访问令牌：</p><ol><li>登录插件市场。</li><li>点击顶部导航栏的 <strong>「我的」</strong>。</li><li>找到 <strong>「插件市场访问令牌」</strong> 区域。</li><li>如果还没有令牌，点击 <strong>「生成令牌」</strong>。</li><li>页面会显示 <strong>「新令牌」</strong>，点击 <strong>「复制令牌」</strong>。</li><li>回到 Neo-MoFox，按主程序或 WebUI 的提示把这个令牌填入插件市场同步配置。</li></ol><div class="warning custom-block"><p class="custom-block-title">令牌只在生成时完整显示</p><p>请在生成后立刻复制并妥善保存。重新生成令牌会让旧令牌立即失效；点击 <strong>「撤销」</strong> 后，Neo-MoFox 将无法继续使用该令牌从市场同步订阅。</p></div><div class="tip custom-block"><p class="custom-block-title">哪些情况不需要令牌？</p><p>只有<strong>已经安装到本地的 <code>.mfp</code> 插件</strong>，并且该插件已经在插件市场注册，Neo-MoFox 才能在不配置访问令牌的情况下处理更新检查。想要同步你的市场订阅列表、自动下载订阅插件，仍然需要配置访问令牌。</p></div><h2 id="通过-git-clone-安装插件-开发者-特殊情况" tabindex="-1">通过 Git Clone 安装插件（开发者 / 特殊情况） <a class="header-anchor" href="#通过-git-clone-安装插件-开发者-特殊情况" aria-label="Permalink to “通过 Git Clone 安装插件（开发者 / 特殊情况）”">​</a></h2><p>如果插件作者提供了 Git 仓库地址，你也可以通过 <code>git clone</code> 的方式安装：</p><ol><li><strong>获取仓库地址</strong>：在插件市场、插件详情页或插件说明中查找 Git 仓库地址。</li><li><strong>进入插件目录</strong>：</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/Neo-MoFox/plugins</span></span></code></pre></div><ol start="3"><li><strong>克隆仓库</strong>：</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">插件的</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 仓库地</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">址</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><ol start="4"><li><strong>安装依赖</strong>（如果需要）：</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">插件目</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">录</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 如果有的话</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">注意</p><p>大部分情况下 Neo-MoFox 会自动安装插件依赖。如果插件说明里提到了额外的 Python 包，按插件作者说明处理即可。</p></div><ol start="5"><li><strong>配置插件</strong>：根据插件说明文档进行配置。</li></ol><h2 id="重启-neo-mofox" tabindex="-1">重启 Neo-MoFox <a class="header-anchor" href="#重启-neo-mofox" aria-label="Permalink to “重启 Neo-MoFox”">​</a></h2><p>无论通过哪种方式安装，为了让新插件生效，你都需要<strong>重启 Neo-MoFox</strong>。</p><h2 id="验证安装" tabindex="-1">验证安装 <a class="header-anchor" href="#验证安装" aria-label="Permalink to “验证安装”">​</a></h2><p>重启后，如何确认插件是否成功加载？很简单，查看日志。</p><p>在 Neo-MoFox 的 <code>logs</code> 文件夹中，找到最新的日志文件并打开。如果你看到类似下面这样的日志，就说明插件已经成功加载：</p><div class="language-log"><button title="Copy Code" class="copy"></button><span class="lang">log</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">21:58:25</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] plugin_manager | </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">INFO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> | ✅ 插件 </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;xxxxxx&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 的组件注册完成</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">21:58:25</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] plugin_manager | </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">INFO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> | ✅ 插件加载成功: xxxxx </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">vX.X.X</span></span></code></pre></div><p>恭喜你，现在你已经成功安装了一个新的插件！快去体验一下它带来的新功能吧！</p><h2 id="更新插件" tabindex="-1">更新插件 <a class="header-anchor" href="#更新插件" aria-label="Permalink to “更新插件”">​</a></h2><h3 id="方式一-订阅并配置访问令牌-推荐" tabindex="-1">方式一：订阅并配置访问令牌（推荐） <a class="header-anchor" href="#方式一-订阅并配置访问令牌-推荐" aria-label="Permalink to “方式一：订阅并配置访问令牌（推荐）”">​</a></h3><ol><li>打开插件市场中的插件详情页。</li><li>在右侧 <strong>「安装」</strong> 面板点击 <strong>「订阅更新」</strong>。</li><li>点击顶部导航栏的 <strong>「我的」</strong>。</li><li>在 <strong>「插件市场访问令牌」</strong> 区域点击 <strong>「生成令牌」</strong> 或 <strong>「重新生成令牌」</strong>。</li><li>点击 <strong>「复制令牌」</strong>。</li><li>回到 Neo-MoFox，按主程序或 WebUI 的提示把令牌填入插件市场同步配置。</li><li>Neo-MoFox 后续即可同步订阅列表，并处理订阅插件的下载与更新。</li></ol><h3 id="方式二-手动下载新版本" tabindex="-1">方式二：手动下载新版本 <a class="header-anchor" href="#方式二-手动下载新版本" aria-label="Permalink to “方式二：手动下载新版本”">​</a></h3><ol><li>打开插件市场中的插件详情页。</li><li>查看右侧 <strong>「安装」</strong> 面板中的最新稳定版。</li><li>点击 <strong>「下载插件」</strong> 下载新版本。</li><li>将新版本插件包放入 <code>plugins</code> 目录，按提示覆盖或替换旧版本。</li><li>重启 Neo-MoFox。</li></ol><h3 id="方式三-git-更新" tabindex="-1">方式三：Git 更新 <a class="header-anchor" href="#方式三-git-更新" aria-label="Permalink to “方式三：Git 更新”">​</a></h3><p>如果你是通过 Git Clone 安装的插件，可以进入插件目录执行：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span></span></code></pre></div><p>更新后同样需要重启 Neo-MoFox。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to “常见问题”">​</a></h2><h3 id="如何找到特定的插件" tabindex="-1">如何找到特定的插件？ <a class="header-anchor" href="#如何找到特定的插件" aria-label="Permalink to “如何找到特定的插件？”">​</a></h3><p>推荐先在插件市场查找：</p><ul><li>使用顶部搜索框搜索插件名称、作者或标签。</li><li>点击 <strong>「推荐」</strong> 查看推荐插件。</li><li>点击 <strong>「浏览」</strong> 按分类查找。</li><li>在插件详情页查看依赖、评论、评分和版本信息。</li></ul><p>如果插件市场找不到，可以联系插件作者确认是否已经上架，或查看插件详情页中提供的主页、仓库、发布页等外部链接。</p><h3 id="插件下载后无法加载怎么办" tabindex="-1">插件下载后无法加载怎么办？ <a class="header-anchor" href="#插件下载后无法加载怎么办" aria-label="Permalink to “插件下载后无法加载怎么办？”">​</a></h3><ol><li><strong>检查文件位置</strong>：确保插件文件放在正确的 <code>plugins</code> 目录下。</li><li><strong>检查文件完整性</strong>：确认下载的文件没有损坏。</li><li><strong>查看日志</strong>：检查 <code>logs</code> 目录下的日志文件，查找错误信息。</li><li><strong>检查依赖</strong>：确认是否安装了插件所需的 Python 依赖包。</li><li><strong>检查版本兼容性</strong>：确认插件支持你当前的 Neo-MoFox 版本。</li><li><strong>寻求帮助</strong>：在插件市场评论区询问，或联系插件作者。</li></ol><h3 id="点击-下载插件-后没有反应怎么办" tabindex="-1">点击“下载插件”后没有反应怎么办？ <a class="header-anchor" href="#点击-下载插件-后没有反应怎么办" aria-label="Permalink to “点击“下载插件”后没有反应怎么办？”">​</a></h3><ol><li>检查浏览器是否拦截了弹窗或下载。</li><li>尝试切换到插件详情页的 <strong>「版本」</strong> 标签，点击具体版本右侧的 <strong>「下载」</strong>。</li><li>换一个浏览器重试。</li><li>如果仍然失败，可以去插件作者提供的 GitHub Release 或其他发布页下载。</li></ol><h3 id="订阅更新后还需要配置-access-token-吗" tabindex="-1">订阅更新后还需要配置 access token 吗？ <a class="header-anchor" href="#订阅更新后还需要配置-access-token-吗" aria-label="Permalink to “订阅更新后还需要配置 access token 吗？”">​</a></h3><p>如果只是更新<strong>已经安装的 <code>.mfp</code> 插件</strong>，并且这个插件已经在插件市场注册，Neo-MoFox 可以不依赖 access token 进行更新检查。</p><p>如果你希望 Neo-MoFox 同步你的市场订阅列表、自动下载订阅插件，仍然需要配置 access token。配置方法：进入插件市场顶部导航栏 <strong>「我的」</strong> → <strong>「插件市场访问令牌」</strong> → <strong>「生成令牌」</strong> → <strong>「复制令牌」</strong>，再按 Neo-MoFox 主程序或 WebUI 的提示填写。</p><h2 id="参与插件开发" tabindex="-1">参与插件开发 <a class="header-anchor" href="#参与插件开发" aria-label="Permalink to “参与插件开发”">​</a></h2><p>如果你对 Neo-MoFox 的插件开发感兴趣，想要为社区贡献自己的一份力量，我们非常欢迎！</p><p>我们为你准备了详细的插件开发文档，希望能帮助你快速上手。</p>`,68)),o("p",null,[s(e,{href:"./../development/plugin_develop/"},{default:n(()=>[...i[4]||(i[4]=[t("前往插件开发指南",-1)])]),_:1})]),s(h),s(g)])}const E=p(c,[["render",b]]);export{y as __pageData,E as default};
